                j = j + 1;
                ()
            }
        } else {
            vec_push(result, vec_get(arr1, i));
            i = i + 1;
            ()
        };
        ()
    };

    while j < len2 {
        vec_push(result, vec_get(arr2, j));
        j = j + 1;
        ()
    };

    result
};

